const express = require('express');
const cors = require('cors');
const path = require('path');
require('dotenv').config();

const authRoutes         = require('./routes/auth');
const reportRoutes       = require('./routes/reports');
const policeRoutes       = require('./routes/police');
const challanRoutes      = require('./routes/challans');
const analyticsRoutes    = require('./routes/analytics');
const appealsRoutes      = require('./routes/appeals');
const rulesRoutes        = require('./routes/rules');
const vehiclesRoutes     = require('./routes/vehicles');
const notifRoutes        = require('./routes/notifications');
const rewardsRoutes      = require('./routes/rewards');
const adminRoutes        = require('./routes/admin');
const weatherRoutes      = require('./routes/weather');
const hotspotRoutes      = require('./routes/hotspots');

const app = express();
const PORT = process.env.PORT || 5000;

app.use(cors());
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    const ms = Date.now() - start;
    let emoji = '🌐';
    if (req.method === 'POST') emoji = '📥';
    if (req.method === 'PUT') emoji = '🔄';
    if (req.method === 'DELETE') emoji = '❌';
    
    if (!req.url.startsWith('/uploads')) {
      console.log(`${emoji} [Frontend ➡️ Backend] ${req.method} ${req.url} — ✅ Status: ${res.statusCode} (${ms}ms)`);
    }
  });
  next();
});

const uploadsDir = path.join(__dirname, '../server/uploads');
app.use('/uploads', express.static(uploadsDir));
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

app.get('/api/health', (req, res) => {
  res.json({ status: 'OK', timestamp: new Date().toISOString() });
});

app.use('/api/auth',                  authRoutes);
app.use('/api/reports',               reportRoutes);
app.use('/api/police',                policeRoutes);
app.use('/api/challans',              challanRoutes);
app.use('/api/analytics',             analyticsRoutes);
app.use('/api/appeals',               appealsRoutes);
app.use('/api/rules',                 rulesRoutes);
app.use('/api/vehicles',              vehiclesRoutes);
app.use('/api/citizen/notifications', notifRoutes);
app.use('/api/citizen/rewards',       rewardsRoutes);
app.use('/api/admin',                 adminRoutes);
app.use('/api/weather',               weatherRoutes);
app.use('/api/hotspots',              hotspotRoutes);

app.use((req, res) => {
  console.log('404:', req.method, req.url);
  res.status(404).json({ error: 'Endpoint not found: ' + req.method + ' ' + req.url });
});

app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error.' });
});

app.listen(PORT, () => {
  console.log(`Traffic Violation API server running on http://localhost:${PORT}`);
});
